public boolean isOneEditDistance(String s, String t) {
    int m = s.length();
    int n = t.length();

    if (Math.abs(m - n) > 1) return false;

    int i = 0, j = 0;
    int diff = 0;

    while (i < m && j < n) {
        if (s.charAt(i) == t.charAt(j)) {
            i++;
            j++;
        } else {
            diff++;
            if (diff > 1) return false;

            if (m > n) {
                i++;
            } else if (m < n) {
                j++;
            } else {
                i++;
                j++;
            }
        }
    }

    if (i < m || j < n) diff++;

    return diff == 1;
