def is_one_edit_distance(s: str, t: str) -> bool:
    m, n = len(s), len(t)
    if abs(m - n) > 1:
        return False
    i = j = diff = 0
    while i < m and j < n:
        if s[i] == t[j]:
            i += 1
            j += 1
        else:
            diff += 1
            if diff > 1:
                return False
            if m > n:
                i += 1
            elif m < n:
                j += 1
            else:
                i += 1
                j += 1
    if i < m or j < n:
        diff += 1
    return diff == 1
